import{_ as l,o as i,c as e,ag as r}from"./chunks/framework.f_9xDHrT.js";const m=JSON.parse('{"title":"安装说明","description":"安装 XIVLauncher CN、启用 Dalamud，并添加 MissFisher 第三方仓库。","frontmatter":{"title":"安装说明","description":"安装 XIVLauncher CN、启用 Dalamud，并添加 MissFisher 第三方仓库。"},"headers":[],"relativePath":"manual/install.md","filePath":"manual/install.md","lastUpdated":1777727305000}'),o={name:"manual/install.md"};function s(n,a,t,h,c,d){return i(),e("div",null,[...a[0]||(a[0]=[r('<h1 id="安装指南" tabindex="-1">安装指南 <a class="header-anchor" href="#安装指南" aria-label="Permalink to &quot;安装指南&quot;">​</a></h1><h2 id="环境依赖" tabindex="-1">环境依赖 <a class="header-anchor" href="#环境依赖" aria-label="Permalink to &quot;环境依赖&quot;">​</a></h2><h2 id="部署-dalamud" tabindex="-1">部署 Dalamud <a class="header-anchor" href="#部署-dalamud" aria-label="Permalink to &quot;部署 Dalamud&quot;">​</a></h2><p>Dalamud 是一个完全免费的 FF14 插件平台。<br> 你需要从 XIVLauncher 启动游戏，才能使用 Dalamud。</p><h2 id="xivlauncher-cn-soil" tabindex="-1">XIVLauncher CN (Soil) <a class="header-anchor" href="#xivlauncher-cn-soil" aria-label="Permalink to &quot;XIVLauncher CN (Soil)&quot;">​</a></h2><p>XIVLauncher 是比官方启动器更便捷的第三方 FF14 启动器。</p><ul><li><p>Soil 版本是什么？<br> XIVLauncher CN (Soil) 是 XIVLauncher CN（蓝月）的分支版本，社区里通常称它为“橙月”。</p></li><li><p>为什么更推荐使用橙月？</p><ul><li>游戏更新后，橙月通常能更快提供对 Dalamud 的适配，让你更早用上插件。</li><li>中国服社区相当一部分主流插件基于橙月内核开发，因此能获得更好的兼容性与支持。</li><li>另外，橙月移除了主库存在的部分不必要限制，并优化了整体逻辑。</li></ul></li></ul><h3 id="安装并打开-xivlauncher-cn-soil" tabindex="-1">安装并打开 XIVLauncher CN (Soil) <a class="header-anchor" href="#安装并打开-xivlauncher-cn-soil" aria-label="Permalink to &quot;安装并打开 XIVLauncher CN (Soil)&quot;">​</a></h3><ol><li><a href="https://github.com/AtmoOmen/FFXIVQuickLauncher/releases/latest/download/XIVLauncherCN-win-Portable.zip" target="_blank" rel="noreferrer">下载 XIVLauncher CN (Soil).zip</a></li><li>解压下载好的 XIVLauncherCN-win-Portable.zip 中的文件到合适的位置。</li><li>打开解压后路径下的 XIVLauncherCN.exe</li></ol><h3 id="设置-xivlauncher-cn-soil-并用它来启动游戏" tabindex="-1">设置 XIVLauncher CN (Soil) 并用它来启动游戏 <a class="header-anchor" href="#设置-xivlauncher-cn-soil-并用它来启动游戏" aria-label="Permalink to &quot;设置 XIVLauncher CN (Soil) 并用它来启动游戏&quot;">​</a></h3><ol><li>点击 XIVLauncher CN (Soil) 界面右下角齿轮图标</li><li>设置游戏文件夹路径</li><li>选择 Dalamud 页签 - 确认已勾选 启用 Dalamud</li><li>点击右下角的 提钩 按钮来保存设置</li><li>从 XIVLauncher CN (Soil) 登陆并启动游戏，Dalamud 应会自动注入游戏进程</li></ol><hr><h2 id="安装-missfisher" tabindex="-1">安装 MissFisher <a class="header-anchor" href="#安装-missfisher" aria-label="Permalink to &quot;安装 MissFisher&quot;">​</a></h2><blockquote><p>以下指引是基于 XIVLauncher CN (Soil) 的，可能与其他版本略有不同，请留意</p></blockquote><h3 id="打开-dalamud-插件安装器" tabindex="-1">打开 Dalamud 插件安装器 <a class="header-anchor" href="#打开-dalamud-插件安装器" aria-label="Permalink to &quot;打开 Dalamud 插件安装器&quot;">​</a></h3><p>已登陆角色时：</p><ol><li>在游戏中按下键盘上的 <code>Esc</code></li><li>点击 <code>Dalamud插件</code></li></ol><p>在标题画面时：</p><ol><li>在游戏标题画面左侧找到 Dalamud 图标</li><li>移动鼠标到图标上 - 点击 插件安装器</li></ol><h3 id="添加第三方仓库链接并安装-missfisher" tabindex="-1">添加第三方仓库链接并安装 MissFisher <a class="header-anchor" href="#添加第三方仓库链接并安装-missfisher" aria-label="Permalink to &quot;添加第三方仓库链接并安装 MissFisher&quot;">​</a></h3><ol><li>点击插件安装器下方的 <code>设置</code></li><li>选择 <code>插件</code> 页签</li><li>在 <code>插件</code> 页面再次点击 <code>第三方插件</code> 页签</li><li>在空的输入框中填写 MissFisher 的仓库链接：</li></ol><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://raw.githubusercontent.com/BlackCleaverLoli/MissFisher/refs/heads/main/MissFisher.json</span></span></code></pre></div><ol start="5"><li>点击 <code>＋</code> 以添加</li><li>点击保存按钮（软盘图标）</li><li>返回插件安装器，搜索 <code>MissFisher</code></li><li>点击安装并等待完成</li></ol>',23)])])}const p=l(o,[["render",s]]);export{m as __pageData,p as default};
